        writeln!(client_h, "    None = 0,");
        writeln!(client_h, "    HostCallFailure = 1,");
        writeln!(client_h, "    NotInTransaction = 2,");
        writeln!(client_h, "    BsatnDecodeError = 3,");
        writeln!(client_h, "    NoSuchTable = 4,");
        writeln!(client_h, "    NoSuchIndex = 5,");
        writeln!(client_h, "    IndexNotUnique = 6,");
        writeln!(client_h, "    NoSuchRow = 7,");
        writeln!(client_h, "    UniqueConstraintViolation = 8,");
        writeln!(client_h, "    ScheduleAtDelayTooLong = 9,");
        writeln!(client_h, "    BufferTooSmall = 10,");
        writeln!(client_h, "    NoSuchIter = 11,");
        writeln!(client_h, "    NoSuchBytes = 12,");
        writeln!(client_h, "    NoSpace = 13,");
        writeln!(client_h, "    ConnectionFailed = 14,");
        writeln!(client_h, "    NetworkTimeout = 15,");
        writeln!(client_h, "    AuthenticationFailed = 16,");
        writeln!(client_h, "    SerializationError = 17,");
        writeln!(client_h, "    InvalidParameter = 18,");
