        writeln!(client_h);

        writeln!(client_h, "// Error Context Structure (like C# ErrorContext)");
        writeln!(client_h, "USTRUCT(BlueprintType)");
        writeln!(client_h, "struct FSpacetimeErrorContext");
        writeln!(client_h, "{{");
        writeln!(client_h, "    GENERATED_BODY()");
        writeln!(client_h);
