// Helper functions to map BSATN read/write methods for primitive types
fn get_bsatn_write_method(prim_type: &PrimitiveType) -> &'static str {
    match prim_type {
        PrimitiveType::Bool => "WriteBool",
        PrimitiveType::I8 => "WriteI8",
        PrimitiveType::U8 => "WriteU8", 
        PrimitiveType::I16 => "WriteI16",
        PrimitiveType::U16 => "WriteU16",
        PrimitiveType::I32 => "WriteI32",
        PrimitiveType::U32 => "WriteU32",
        PrimitiveType::I64 => "WriteI64",
        PrimitiveType::U64 => "WriteU64",
        PrimitiveType::F32 => "WriteF32",
        PrimitiveType::F64 => "WriteF64",
        _ => "WriteGeneric",
    }
}

fn get_bsatn_read_method(prim_type: &PrimitiveType) -> &'static str {
    match prim_type {
        PrimitiveType::Bool => "ReadBool",
        PrimitiveType::I8 => "ReadI8",
        PrimitiveType::U8 => "ReadU8",
        PrimitiveType::I16 => "ReadI16", 
        PrimitiveType::U16 => "ReadU16",
        PrimitiveType::I32 => "ReadI32",
        PrimitiveType::U32 => "ReadU32",
        PrimitiveType::I64 => "ReadI64",
        PrimitiveType::U64 => "ReadU64",
        PrimitiveType::F32 => "ReadF32",
        PrimitiveType::F64 => "ReadF64",
        _ => "ReadGeneric",
    }
}

// Helper function to generate primitive type serialization
fn generate_primitive_serialization(output: &mut UnrealCppAutogen, field_name: &str, prim_type: &PrimitiveType) {
    match prim_type {
        PrimitiveType::Bool => {
            writeln!(output, "    OutBytes.Add({} ? 0x00 : 0x01); // BSATN bool encoding", field_name);
        }
        PrimitiveType::I8 => {
            writeln!(output, "    OutBytes.Add(static_cast<uint8>({})); // BSATN i8 encoding", field_name);
        }
        PrimitiveType::U8 => {
            writeln!(output, "    OutBytes.Add({}); // BSATN u8 encoding", field_name);
        }
        PrimitiveType::I16 => {
            writeln!(output, "    // BSATN i16 encoding (little-endian)");
            writeln!(output, "    OutBytes.Add(static_cast<uint8>({} & 0xFF));", field_name);
            writeln!(output, "    OutBytes.Add(static_cast<uint8>(({} >> 8) & 0xFF));", field_name);
        }
        PrimitiveType::U16 => {
            writeln!(output, "    // BSATN u16 encoding (little-endian)");
            writeln!(output, "    OutBytes.Add(static_cast<uint8>({} & 0xFF));", field_name);
            writeln!(output, "    OutBytes.Add(static_cast<uint8>(({} >> 8) & 0xFF));", field_name);
        }
        PrimitiveType::I32 => {
            writeln!(output, "    // BSATN i32 encoding (little-endian)");
            writeln!(output, "    for (int i = 0; i < 4; ++i)");
            writeln!(output, "    {{");
            writeln!(output, "        OutBytes.Add(static_cast<uint8>(({} >> (i * 8)) & 0xFF));", field_name);
            writeln!(output, "    }}");
        }
        PrimitiveType::U32 => {
            writeln!(output, "    // BSATN u32 encoding (little-endian)");
            writeln!(output, "    for (int i = 0; i < 4; ++i)");
            writeln!(output, "    {{");
            writeln!(output, "        OutBytes.Add(static_cast<uint8>(({} >> (i * 8)) & 0xFF));", field_name);
            writeln!(output, "    }}");
        }
        PrimitiveType::I64 => {
            writeln!(output, "    // BSATN i64 encoding (little-endian)");
            writeln!(output, "    for (int i = 0; i < 8; ++i)");
            writeln!(output, "    {{");
            writeln!(output, "        OutBytes.Add(static_cast<uint8>(({} >> (i * 8)) & 0xFF));", field_name);
            writeln!(output, "    }}");
        }
        PrimitiveType::U64 => {
            writeln!(output, "    // BSATN u64 encoding (little-endian)");
            writeln!(output, "    for (int i = 0; i < 8; ++i)");
            writeln!(output, "    {{");
            writeln!(output, "        OutBytes.Add(static_cast<uint8>(({} >> (i * 8)) & 0xFF));", field_name);
            writeln!(output, "    }}");
        }
        PrimitiveType::F32 => {
            writeln!(output, "    // BSATN f32 encoding (IEEE 754, little-endian)");
            writeln!(output, "    uint32 FloatBits = *reinterpret_cast<const uint32*>(&{});", field_name);
            writeln!(output, "    for (int i = 0; i < 4; ++i)");
            writeln!(output, "    {{");
            writeln!(output, "        OutBytes.Add(static_cast<uint8>((FloatBits >> (i * 8)) & 0xFF));");
            writeln!(output, "    }}");
        }
        PrimitiveType::F64 => {
            writeln!(output, "    // BSATN f64 encoding (IEEE 754, little-endian)");
            writeln!(output, "    uint64 DoubleBits = *reinterpret_cast<const uint64*>(&{});", field_name);
            writeln!(output, "    for (int i = 0; i < 8; ++i)");
            writeln!(output, "    {{");
            writeln!(output, "        OutBytes.Add(static_cast<uint8>((DoubleBits >> (i * 8)) & 0xFF));");
            writeln!(output, "    }}");
        }
        _ => {
            writeln!(output, "    // TODO: Implement serialization for primitive type: {:?}", prim_type);
        }
    }
}

// Helper function to generate primitive type deserialization
fn generate_primitive_deserialization(output: &mut UnrealCppAutogen, field_name: &str, prim_type: &PrimitiveType) {
    match prim_type {
        PrimitiveType::Bool => {
            writeln!(output, "    if (Offset < InBytes.Num())");
            writeln!(output, "    {{");
            writeln!(output, "        {} = (InBytes[Offset++] == 0x00); // BSATN bool decoding", field_name);
            writeln!(output, "    }}");
        }
        PrimitiveType::I8 => {
            writeln!(output, "    if (Offset < InBytes.Num())");
            writeln!(output, "    {{");
            writeln!(output, "        {} = static_cast<int8>(InBytes[Offset++]); // BSATN i8 decoding", field_name);
            writeln!(output, "    }}");
        }
        PrimitiveType::U8 => {
            writeln!(output, "    if (Offset < InBytes.Num())");
            writeln!(output, "    {{");
            writeln!(output, "        {} = InBytes[Offset++]; // BSATN u8 decoding", field_name);
            writeln!(output, "    }}");
        }
        _ => {
            writeln!(output, "    // TODO: Implement deserialization for primitive type: {:?}", prim_type);
            writeln!(output, "    // Offset += sizeof_primitive_type();");
        }
    }
}

fn generate_string_serialization(output: &mut UnrealCppAutogen, field_name: &str) {
    writeln!(output, "    // BSATN string encoding (u32 length + UTF-8 bytes)");
    writeln!(output, "    FTCHARToUTF8 UTF8String(*{});", field_name);
    writeln!(output, "    uint32 StringLength = UTF8String.Length();");
    writeln!(output, "    // Write length (u32, little-endian)");
    writeln!(output, "    for (int i = 0; i < 4; ++i)");
    writeln!(output, "    {{");
    writeln!(output, "        OutBytes.Add(static_cast<uint8>((StringLength >> (i * 8)) & 0xFF));");
    writeln!(output, "    }}");
    writeln!(output, "    // Write UTF-8 bytes");
    writeln!(output, "    for (int i = 0; i < StringLength; ++i)");
    writeln!(output, "    {{");
    writeln!(output, "        OutBytes.Add(static_cast<uint8>(UTF8String.Get()[i]));");
    writeln!(output, "    }}");
}

fn generate_string_deserialization(output: &mut UnrealCppAutogen, field_name: &str) {
    writeln!(output, "    // BSATN string decoding (u32 length + UTF-8 bytes)");
    writeln!(output, "    if (Offset + 4 <= InBytes.Num())");
    writeln!(output, "    {{");
    writeln!(output, "        uint32 StringLength = 0;");
    writeln!(output, "        // Read length (u32, little-endian)");
    writeln!(output, "        for (int i = 0; i < 4; ++i)");
    writeln!(output, "        {{");
    writeln!(output, "            StringLength |= (static_cast<uint32>(InBytes[Offset++]) << (i * 8));");
    writeln!(output, "        }}");
    writeln!(output, "        // Read UTF-8 bytes");
    writeln!(output, "        if (Offset + StringLength <= InBytes.Num())");
    writeln!(output, "        {{");
    writeln!(output, "            TArray<uint8> UTF8Bytes;");
    writeln!(output, "            UTF8Bytes.SetNum(StringLength + 1); // +1 for null terminator");
    writeln!(output, "            for (uint32 i = 0; i < StringLength; ++i)");
    writeln!(output, "            {{");
    writeln!(output, "                UTF8Bytes[i] = InBytes[Offset++];");
    writeln!(output, "            }}");
    writeln!(output, "            UTF8Bytes[StringLength] = 0; // Null terminator");
    writeln!(output, "            {} = FString(UTF8_TO_TCHAR(reinterpret_cast<const char*>(UTF8Bytes.GetData())));", field_name);
    writeln!(output, "        }}");
    writeln!(output, "    }}");
}

fn generate_identity_serialization(output: &mut UnrealCppAutogen, field_name: &str) {
    writeln!(output, "    // BSATN Identity encoding (32 bytes, little-endian U256)");
    writeln!(output, "    // Identity is stored as a product with a single __identity__ field of type U256");
    writeln!(output, "    TArray<uint8> IdentityBytes = {}.ToBytes();", field_name);
    writeln!(output, "    // Ensure we have exactly 32 bytes for U256");
    writeln!(output, "    if (IdentityBytes.Num() == 32)");
    writeln!(output, "    {{");
    writeln!(output, "        // Write the 32 bytes directly (little-endian format)");
    writeln!(output, "        for (int i = 0; i < 32; ++i)");
    writeln!(output, "        {{");
    writeln!(output, "            OutBytes.Add(IdentityBytes[i]);");
    writeln!(output, "        }}");
    writeln!(output, "    }}");
    writeln!(output, "    else");
    writeln!(output, "    {{");
    writeln!(output, "        UE_LOG(LogTemp, Error, TEXT(\"Identity serialization failed: expected 32 bytes, got %d\"), IdentityBytes.Num());");
    writeln!(output, "    }}");
}

fn generate_identity_deserialization(output: &mut UnrealCppAutogen, field_name: &str) {
    writeln!(output, "    // BSATN Identity decoding (32 bytes, little-endian U256)");
    writeln!(output, "    if (Offset + 32 <= InBytes.Num())");
    writeln!(output, "    {{");
    writeln!(output, "        TArray<uint8> IdentityBytes;");
    writeln!(output, "        IdentityBytes.SetNum(32);");
    writeln!(output, "        // Read 32 bytes for the U256 identity");
    writeln!(output, "        for (int i = 0; i < 32; ++i)");
    writeln!(output, "        {{");
    writeln!(output, "            IdentityBytes[i] = InBytes[Offset++];");
    writeln!(output, "        }}");
    writeln!(output, "        // Create Identity from bytes (little-endian)");
    writeln!(output, "        {} = FSpacetimeDBIdentity::FromBytes(IdentityBytes);", field_name);
    writeln!(output, "    }}");
    writeln!(output, "    else");
    writeln!(output, "    {{");
    writeln!(output, "        UE_LOG(LogTemp, Error, TEXT(\"Identity deserialization failed: not enough bytes\"));");
    writeln!(output, "    }}");
}

struct UnrealCppAutogen {
    output: CodeIndenter<String>,
}

impl Deref for UnrealCppAutogen {
    type Target = CodeIndenter<String>;
    fn deref(&self) -> &Self::Target { &self.output }
}
impl std::ops::DerefMut for UnrealCppAutogen {
    fn deref_mut(&mut self) -> &mut Self::Target { &mut self.output }
}

impl UnrealCppAutogen {
    fn new(extra_includes: &[&str], self_header: &str) -> Self {
        let mut output = CodeIndenter::new(String::new(), "    ");
        print_auto_generated_file_comment(&mut output);
        writeln!(output, "#pragma once");
        writeln!(output, "#include \"CoreMinimal.h\"");
        for include in extra_includes { writeln!(output, "#include \"{}\"", include); }
        writeln!(output, "#include \"{}.g.generated.h\"", self_header); // need to include the generated header for Unreal's reflection
        writeln!(output);
        Self { output }
    }

    fn new_cpp(extra_includes: &[&str]) -> Self {
        let mut output = CodeIndenter::new(String::new(), "    ");
        print_auto_generated_file_comment(&mut output);
        for include in extra_includes { writeln!(output, "#include \"{}\"", include); }
        writeln!(output);
        Self { output }
    }

    fn into_inner(self) -> String { self.output.into_inner() }
}

