//  Helpers
// ---------------------------------------------------------------------------

use std::collections::HashSet;

fn autogen_cpp_struct(
    module: &ModuleDef,
    name: &str, // Changed to &str
    product_type: &ProductTypeDef,
) -> String {
    let mut headers = HashSet::<String>::new();

    for (_, field_ty) in product_type {
        collect_includes_for_type(module, field_ty, &mut headers);
    }

    // Convert to `Vec<&str>` so UnrealCppAutogen::new works
    let mut slices: Vec<&str> = headers.iter().map(|s| s.as_str()).collect();
    slices.sort(); // make output deterministic

    // --------- start writing file ---------
    let mut output = UnrealCppAutogen::new(&slices, name);

    writeln!(output, "USTRUCT(BlueprintType)");
    writeln!(output, "struct F{}", name);
    writeln!(output, "{{");
    output.indent(1);
    writeln!(output, "GENERATED_BODY()");
    writeln!(output);

    // Generate fields with optional handling
    let mut has_optionals = false;
    for (orig_name, ty) in product_type.into_iter() {
        let field_name = orig_name.to_string();
        let is_optional = matches!(ty, AlgebraicTypeUse::Option(_));
        
        if is_optional {
            has_optionals = true;
            if let AlgebraicTypeUse::Option(inner) = ty {
                let inner_ty_str = cpp_ty_fmt(module, inner).to_string();
                
                // Generate the actual field (non-optional for Blueprint compatibility)
                writeln!(output, "UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"SpacetimeDB\", meta=(DisplayName=\"{} (Optional)\"))", field_name.to_case(Case::Title));
                writeln!(output, "{} {};", inner_ty_str, field_name);
                writeln!(output);
                
                // Generate a separate bool to track if the optional has a value
                writeln!(output, "UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"SpacetimeDB\", meta=(DisplayName=\"Has {}\"))", field_name.to_case(Case::Title));
                writeln!(output, "bool b{}HasValue = false;", field_name.to_case(Case::Pascal));
                writeln!(output);
            }
        } else {
            let ty_str = cpp_ty_fmt(module, ty).to_string();
            writeln!(output, "UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"SpacetimeDB\")");
            writeln!(output, "{} {};", ty_str, field_name);
            writeln!(output);
        }
    }

    // Default constructor
    writeln!(output, "F{}() = default;", name);
    writeln!(output);
    
    // Helper methods for optional fields
    if has_optionals {
        writeln!(output, "// Helper methods for optional fields");
        for (orig_name, ty) in product_type.into_iter() {
            if let AlgebraicTypeUse::Option(inner) = ty {
                let field_name = orig_name.to_string();
                let pascal_name = field_name.to_case(Case::Pascal);
                let inner_ty_str = cpp_ty_fmt(module, inner).to_string();
                
                // Getter that checks if value exists
                writeln!(output, "UFUNCTION(BlueprintCallable, BlueprintPure, Category=\"SpacetimeDB\", meta=(DisplayName=\"Get {} (Safe)\"))", pascal_name);
                writeln!(output, "{} Get{}Safe() const", inner_ty_str, pascal_name);
                writeln!(output, "{{");
                writeln!(output, "    return b{}HasValue ? {} : {}();", pascal_name, field_name, inner_ty_str);
                writeln!(output, "}}");
                writeln!(output);
                
                // Setter that updates both value and flag
                writeln!(output, "UFUNCTION(BlueprintCallable, Category=\"SpacetimeDB\", meta=(DisplayName=\"Set {} (Optional)\"))", pascal_name);
                writeln!(output, "void Set{}Optional(const {}& Value)", pascal_name, inner_ty_str);
                writeln!(output, "{{");
                writeln!(output, "    {} = Value;", field_name);
                writeln!(output, "    b{}HasValue = true;", pascal_name);
                writeln!(output, "}}");
                writeln!(output);
                
                // Clear method
                writeln!(output, "UFUNCTION(BlueprintCallable, Category=\"SpacetimeDB\", meta=(DisplayName=\"Clear {}\"))", pascal_name);
                writeln!(output, "void Clear{}()", pascal_name);
                writeln!(output, "{{");
                writeln!(output, "    {} = {}();", field_name, inner_ty_str);
                writeln!(output, "    b{}HasValue = false;", pascal_name);
                writeln!(output, "}}");
                writeln!(output);
            }
        }
    }

    // BSATN Serialization methods
    writeln!(output, "// BSATN Serialization Support");
    writeln!(output, "void WriteToBytes(TArray<uint8>& OutBytes) const;");
    writeln!(output, "void ReadFromBytes(const TArray<uint8>& InBytes);");
    writeln!(output);
    
    // Error handling for BSATN operations
    writeln!(output, "// Error handling for BSATN operations");
    writeln!(output, "UFUNCTION(BlueprintCallable, BlueprintPure, Category=\"SpacetimeDB|Error\")");
    writeln!(output, "FSpacetimeErrorContext GetLastSerializationError() const;");
    writeln!(output);
    
    // Validation methods
    writeln!(output, "// Validation methods");
    writeln!(output, "UFUNCTION(BlueprintCallable, BlueprintPure, Category=\"SpacetimeDB|Validation\")");
    writeln!(output, "bool IsValid() const;");

    output.dedent(1);
    writeln!(output, "}};");

    output.into_inner()
}

// Helper function to generate a C++ enum definition
fn autogen_cpp_enum(name: &str, enum_type: &PlainEnumTypeDef) ->String { // Changed name to &str
    
    let mut output = UnrealCppAutogen::new(&[], name);
    writeln!(output, "UENUM(BlueprintType)");
    writeln!(output, "enum class E{} : uint8", name);
    writeln!(output, "{{");
    output.indent(1);

    for variant in &*enum_type.variants {
        writeln!(output, "{},", variant.deref().to_case(Case::Pascal)); // Ensure variants are PascalCase, common for UE enums
    }

    output.dedent(1);
    writeln!(output, "}};");
    
    output.into_inner()
}

/// Generate Unreal-C++ code for a Rust tagged enum (`sum_type`)
///
/// * `module` – module in which the enum was defined
/// * `name`   – Pascal-case enum name, e.g. `"ClientMessage"`
/// * `sum_type` – parsed `SumTypeDef` containing the variants
///
/// The function returns the fully-formed `.h` body (the caller decides
/// whether to emit a matching `.cpp`; for header-only output, this is
/// enough).
fn autogen_cpp_sum(
    module: &ModuleDef,
    name: &str,
    sum_type: &SumTypeDef,
) -> String {
    use convert_case::{Case};

    /* ------------------------------------------------------------------ */
    /* 1. gather #includes for every variant payload -------------------- */
    /* ------------------------------------------------------------------ */
    let mut includes = HashSet::<String>::new();
    for (_, alg_ty) in &sum_type.variants {
        collect_includes_for_type(module, alg_ty, &mut includes);
    }
   
    // hardcoded include for instanced structs
    includes.insert("StructUtils/InstancedStruct.h".to_string());
    
    let include_slices: Vec<&str> = includes.iter().map(|s| s.as_str()).collect();

    // /* ------------------------------------------------------------------ */
    // /* 2. emit boiler-plate + forward decls ----------------------------- */
    // /* ------------------------------------------------------------------ */
    let mut out = UnrealCppAutogen::new(&include_slices, name);

    /* ------------------------------------------------------------------ */
    /* 3. generate the tag enum ----------------------------------------- */
    /* ------------------------------------------------------------------ */
    writeln!(out, "UENUM(BlueprintType)");
    writeln!(out, "enum class E{}Tag : uint8", name);
    writeln!(out, "{{");
    for (ix, (variant, _)) in sum_type.variants.iter().enumerate() {
        let comma = if ix + 1 == sum_type.variants.len() { "" } else { "," };
        writeln!(out, "    {}{}", variant.to_case(Case::Pascal), comma);
    }
    writeln!(out, "}};");
    writeln!(out);

    /* ------------------------------------------------------------------ */
    /* 4. generate the wrapper UCLASS ----------------------------------- */
    /* ------------------------------------------------------------------ */
    writeln!(out, "UCLASS(BlueprintType)");
    writeln!(out, "class U{} : public UObject", name);
    writeln!(out, "{{");
    writeln!(out, "    GENERATED_BODY()");
    writeln!(out);

    // default ctor
    writeln!(out, "public:");
    writeln!(out, "    U{}() = default;", name);
    writeln!(out);

    // data + tag
    writeln!(out, "    UPROPERTY(EditAnywhere, BlueprintReadWrite, meta=(BaseStruct=\"/Script/Engine.InstancedStruct\"))");
    writeln!(out, "    FInstancedStruct MessageData;");
    writeln!(out);
    writeln!(out, "    UPROPERTY(BlueprintReadWrite)");
    writeln!(out, "    E{}Tag Tag;", name);
    writeln!(out);

    /* 4a. Static factories per variant -------------------------------- */
    for (variant_name, variant_type) in &sum_type.variants {
        let pas = variant_name.to_case(Case::Pascal);
        let param_type = cpp_ty_fmt(module, variant_type).to_string();
        
        writeln!(out, "    UFUNCTION(BlueprintCallable, Category=\"SpacetimeDB\")");
        writeln!(out, "    static U{}* Create{}(const {}& Value)", name, pas, param_type);
        writeln!(out, "    {{");
        writeln!(out, "        U{}* Obj = NewObject<U{}>();", name, name);
        writeln!(out, "        Obj->Tag = E{}Tag::{};", name, pas);
        
        // Initialize variant data based on type
        if is_primitive_or_simple_type(variant_type) {
            // For primitives, create a wrapper struct
            writeln!(out, "        F{}Wrapper Wrapper;", pas);
            writeln!(out, "        Wrapper.Value = Value;");
            writeln!(out, "        Obj->MessageData.InitializeAs<F{}Wrapper>(Wrapper);", pas);
        } else {
            // For complex types, use directly
            writeln!(out, "        Obj->MessageData.InitializeAs<{}>(Value);", param_type);
        }
        
        writeln!(out, "        return Obj;");
        writeln!(out, "    }}");
        writeln!(out);
    }

    /* 4b. Get/Is helpers ---------------------------------------------- */
    for (variant_name, variant_type) in &sum_type.variants {
        let pas = variant_name.to_case(Case::Pascal);
        let return_type = cpp_ty_fmt(module, variant_type).to_string();

        // Is*
        writeln!(out, "    UFUNCTION(BlueprintCallable, BlueprintPure, Category=\"SpacetimeDB\")");
        writeln!(out, "    bool Is{}() const {{ return Tag == E{}Tag::{}; }}", pas, name, pas);
        writeln!(out);

        // TryGet* with proper data extraction
        writeln!(out, "    UFUNCTION(BlueprintCallable, BlueprintPure, Category=\"SpacetimeDB\")");
        writeln!(out, "    bool TryGet{}({}& OutValue) const", pas, return_type);
        writeln!(out, "    {{");
        writeln!(out, "        if (Tag == E{}Tag::{})", name, pas);
        writeln!(out, "        {{");
        
        if is_primitive_or_simple_type(variant_type) {
            writeln!(out, "            const F{}Wrapper* Wrapper = MessageData.GetPtr<F{}Wrapper>();", pas, pas);
            writeln!(out, "            if (Wrapper)");
            writeln!(out, "            {{");
            writeln!(out, "                OutValue = Wrapper->Value;");
            writeln!(out, "                return true;");
            writeln!(out, "            }}");
        } else {
            writeln!(out, "            const {}* Data = MessageData.GetPtr<{}>();", return_type, return_type);
            writeln!(out, "            if (Data)");
            writeln!(out, "            {{");
            writeln!(out, "                OutValue = *Data;");
            writeln!(out, "                return true;");
            writeln!(out, "            }}");
        }
        
        writeln!(out, "        }}");
        writeln!(out, "        return false;");
        writeln!(out, "    }}");
        writeln!(out);

        // GetAs* with default value for convenience
        writeln!(out, "    UFUNCTION(BlueprintCallable, BlueprintPure, Category=\"SpacetimeDB\")");
        writeln!(out, "    {} GetAs{}() const", return_type, pas);
        writeln!(out, "    {{");
        writeln!(out, "        {} Result;", return_type);
        writeln!(out, "        TryGet{}(Result);", pas);
        writeln!(out, "        return Result;");
        writeln!(out, "    }}");
        writeln!(out);
    }

    // Generate wrapper structs for primitive types (outside the main class)
    writeln!(out, "}}; // class {}", name);
    writeln!(out);
    
    // Generate wrapper structs for primitive variants
    for (variant_name, variant_type) in &sum_type.variants {
        if is_primitive_or_simple_type(variant_type) {
            let pas = variant_name.to_case(Case::Pascal);
            let param_type = cpp_ty_fmt(module, variant_type).to_string();
            
            writeln!(out, "// Wrapper struct for {} variant", pas);
            writeln!(out, "USTRUCT(BlueprintType)");
            writeln!(out, "struct F{}Wrapper", pas);
            writeln!(out, "{{");
            writeln!(out, "    GENERATED_BODY()");
            writeln!(out);
            writeln!(out, "    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category=\"SpacetimeDB\")");
            writeln!(out, "    {} Value;", param_type);
            writeln!(out);
            writeln!(out, "    F{}Wrapper() = default;", pas);
            writeln!(out, "    F{}Wrapper(const {}& InValue) : Value(InValue) {{}}", pas, param_type);
            writeln!(out, "}};");
            writeln!(out);
        }
    }

    out.into_inner()
}

// Helper trait for Identifier case conversion
trait IdentifierCasing {
    fn to_case(&self, case: Case) -> String;
}

impl IdentifierCasing for Identifier {
    fn to_case(&self, case: Case) -> String {
        self.deref().to_case(case)
    }
}


fn cpp_ty_fmt<'a>(
    module: &'a ModuleDef,
    ty: &'a AlgebraicTypeUse,
) -> impl fmt::Display + 'a {
    fmt_fn(move |f| match ty {
        // --------- primitives etc ---------
        AlgebraicTypeUse::Primitive(p) => f.write_str(match p {
            PrimitiveType::Bool => "bool",
            PrimitiveType::I8   => "int8",
            PrimitiveType::U8   => "uint8",
            PrimitiveType::I16  => "int16",
            PrimitiveType::U16  => "int32", // uint16 is not supported by Unreal blueprints
            PrimitiveType::I32  => "int32",
            PrimitiveType::U32  => "int64", // uint32 is not supported by Unreal blueprints
            PrimitiveType::I64  => "int64",
            PrimitiveType::U64  => "int64", // TODO: uint64 is not supported by Unreal blueprints. Need to look a way so that we don't lose info here
            PrimitiveType::F32  => "float",
            PrimitiveType::F64  => "double",
            // TODO: assumed
            PrimitiveType::I128 => "FSpacetimeDBInt128",
            PrimitiveType::U128 => "FSpacetimeDBUInt128",
            PrimitiveType::I256 => "FSpacetimeDBInt256",
            PrimitiveType::U256 => "FSpacetimeDBUInt256",
        }),

        // byte-blob ⇒ TArray<uint8>
        AlgebraicTypeUse::Array(elem)
            if matches!(elem.as_ref(), AlgebraicTypeUse::Primitive(PrimitiveType::U8)) =>
                f.write_str("TArray<uint8>"),

        AlgebraicTypeUse::Array(elem) =>
            write!(f, "TArray<{}>", cpp_ty_fmt(module, elem)),

        AlgebraicTypeUse::String         => f.write_str("FString"),
        AlgebraicTypeUse::Identity       => f.write_str("FSpacetimeDBIdentity"),
        AlgebraicTypeUse::ConnectionId   => f.write_str("FSpacetimeDBConnectionId"),
        AlgebraicTypeUse::Timestamp      => f.write_str("FSpacetimeDBTimestamp"),
        AlgebraicTypeUse::TimeDuration   => f.write_str("FSpacetimeDBTimeDuration"),
        AlgebraicTypeUse::ScheduleAt     => f.write_str("FSpacetimeDBScheduleAt"),
        AlgebraicTypeUse::Unit           => f.write_str("FSpacetimeDBUnit"),

        // --------- references to user-defined types ---------
        AlgebraicTypeUse::Ref(r) => {
            let scoped = type_ref_name(module, *r);               // PascalCase
            match &module.typespace_for_generate()[*r] {
                AlgebraicTypeDef::PlainEnum(_) =>
                    write!(f, "E{}", scoped),                     // enum → EFoo
                AlgebraicTypeDef::Product(_) |
                AlgebraicTypeDef::Sum(_)       =>
                    write!(f, "F{}", scoped),                     // struct/record → FFoo
            }
        }

        // Options are *not* wrapped here; we decide optionality at call-site
        AlgebraicTypeUse::Option(inner) =>
            write!(f, "{}", cpp_ty_fmt(module, inner)),

        AlgebraicTypeUse::Never => unreachable!("never type"),
    })
}


// Given an `AlgebraicTypeUse`, add every referenced type's generated
// header name (`"<FTypeName>.g.h"`) into `out` (a `HashSet` avoids dups).
fn collect_includes_for_type(
    module: &ModuleDef,
    ty: &AlgebraicTypeUse,
    out: &mut std::collections::HashSet<String>,
) {
    use AlgebraicTypeUse::*;
    match ty {
        Ref(r) => {
            let header = format!("{}.g.h", type_ref_name(module, *r));
            out.insert(header);
        }
        Option(inner) | Array(inner) => {
            collect_includes_for_type(module, inner, out);
        }
        // primitive / builtin types need no headers
        Identity | ConnectionId | Timestamp | TimeDuration | ScheduleAt
        | Unit | String | Primitive(_) | Never => {}
    }
}


// TODO: Not gonna use it until we sort out the TOptional problem with the BPs
// Helper function to determine if a type needs wrapper struct for sum types
fn is_primitive_or_simple_type(ty: &AlgebraicTypeUse) -> bool {
    matches!(
        ty,
        AlgebraicTypeUse::Primitive(_)
        | AlgebraicTypeUse::String
        | AlgebraicTypeUse::Identity
        | AlgebraicTypeUse::ConnectionId
        | AlgebraicTypeUse::Timestamp
        | AlgebraicTypeUse::TimeDuration
        | AlgebraicTypeUse::ScheduleAt
        | AlgebraicTypeUse::Unit
    )
}

